// -------------------------------------------------------
// ESCENARIO 1: Login + Navegacion a Ficha Alumno
// Representa el flujo completo que hace un asesor al iniciar su jornada
// -------------------------------------------------------
export function scenarioLoginNavegacion() {
  const start = Date.now();

  // Paso 1: SSR - Cargar pagina de login
  const loginPage = http.get(`${SSR_URL}/auth/login`, { tags: { step: 'ssr_login_page' } });
  check(loginPage, {
    'SSR login page 200': (r) => r.status === 200,
    'SSR login TTFB < 800ms': (r) => r.timings.waiting < 800,
  });
  sleep(1);

  // Paso 2: API - Autenticar
  const token = doLogin();
  sleep(0.5);

  if (token) {
    const h = apiHeaders(token);
    const idAlumno = Math.floor(Math.random() * 50) + 1;

    // Paso 3: SSR - Navegar a atencion cliente (navegacion Angular SPA)
    const atcPage = http.get(`${SSR_URL}/atencion-cliente`, { tags: { step: 'ssr_atc_page' } });
    check(atcPage, { 'SSR ATC page 200 o redir': (r) => [200, 302, 307].includes(r.status) });
    sleep(1);

    // Paso 4: API - Cargar datos del alumno (batch como hace Angular forkJoin)
    const fichaStart = Date.now();
    const responses = http.batch([
      ['GET', `${BASE_URL}/AgendaInformacionActividad/ObtenerDatosAlumno?idAlumno=${idAlumno}`,
        null, { headers: h, tags: { step: 'ficha_datos_alumno' } }],
      ['GET', `${BASE_URL}/AgendaInformacionActividad/ObtenerDatosCobranzaAlumno?idAlumno=${idAlumno}`,
        null, { headers: h, tags: { step: 'ficha_cobranza' } }],
      ['GET', `${BASE_URL}/AgendaInformacionActividad/ObtenerSeguimientoAlumnoCategoria?idAlumno=${idAlumno}`,
        null, { headers: h, tags: { step: 'ficha_seguimiento' } }],
      ['GET', `${BASE_URL}/MatriculaCabecera/ObtenerIdentificadoresMatriculaComboPorAlumno?idAlumno=${idAlumno}`,
        null, { headers: h, tags: { step: 'ficha_matriculas' } }],
    ]);
    const fichaDur = Date.now() - fichaStart;
    loginNavDuracion.add(Date.now() - start);

    const fichaOk = check(responses[0], { 'Ficha alumno cargada': (r) => [200, 404].includes(r.status) });
    loginNavFallo.add(fichaOk ? 0 : 1);
  } else {
    loginNavFallo.add(1);
  }

  sleep(Math.random() * 3 + 2);
}

