    sleep(0.5);

    // Actividades del asesor (listado principal)
    r = http.get(`${BASE_URL}/Agenda/ObtenerActividadFiltradaPorAsesor`,
      { headers: h, tags: { step: 'actividades_asesor' } });
    check(r, { 'Actividades asesor 200': (r) => r.status === 200, 'Actividades < 800ms': (r) => r.timings.duration < 800 });
