    // Pagos atrasados (tab frecuente)
    r = http.get(`${BASE_URL}/Agenda/ObtenerActividadFiltradaPorAsesorPagosAtrasados`,
      { headers: h, tags: { step: 'pagos_atrasados' } });
    check(r, { 'PagosAtrasados 200': (r) => r.status === 200 });
    sleep(0.5);

    // Metricas del dashboard
    r = http.get(`${BASE_URL}/Comercial/AgendaActividad/ObtenerMetricasActividadesATC`,
